/**
 * Options for creating an [`LlmSession`]. All fields have defaults, so
 * foreign callers can construct this with only the fields they care about.
 */
public struct GenerationOptions {
    /**
     * Hard cap on new tokens per reply.
     */
    public var maxTokens: UInt32
    /**
     * Sampling temperature. Leaving every sampling field unset selects
     * greedy (deterministic) decoding.
     */
    public var temperature: Float?
    /**
     * Nucleus sampling threshold (0–1).
     */
    public var topP: Float?
    /**
     * Top-k cutoff. `0`/unset disables the filter.
     */
    public var topK: UInt32?
    /**
     * Repetition penalty (1.0 = off).
     */
    public var repetitionPenalty: Float?
    /**
     * Optional system prompt seeded at the start of the conversation.
     */
    public var systemPrompt: String?
    /**
     * Backend override: `auto` (default), `cpu`, `metal`, `wgpu`. Mobile
     * static libs are CPU-only today, so `auto` resolves to CPU there.
     */
    public var backend: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Hard cap on new tokens per reply.
         */maxTokens: UInt32 = UInt32(512), 
        /**
         * Sampling temperature. Leaving every sampling field unset selects
         * greedy (deterministic) decoding.
         */temperature: Float? = nil, 
        /**
         * Nucleus sampling threshold (0–1).
         */topP: Float? = nil, 
        /**
         * Top-k cutoff. `0`/unset disables the filter.
         */topK: UInt32? = nil, 
        /**
         * Repetition penalty (1.0 = off).
         */repetitionPenalty: Float? = nil, 
        /**
         * Optional system prompt seeded at the start of the conversation.
         */systemPrompt: String? = nil, 
        /**
         * Backend override: `auto` (default), `cpu`, `metal`, `wgpu`. Mobile
         * static libs are CPU-only today, so `auto` resolves to CPU there.
         */backend: String? = nil) {
        self.maxTokens = maxTokens
        self.temperature = temperature
        self.topP = topP
        self.topK = topK
        self.repetitionPenalty = repetitionPenalty
        self.systemPrompt = systemPrompt
        self.backend = backend
    }
}

#if compiler(>=6)
extension GenerationOptions: Sendable {}
#endif


extension GenerationOptions: Equatable, Hashable {
    public static func ==(lhs: GenerationOptions, rhs: GenerationOptions) -> Bool {
        if lhs.maxTokens != rhs.maxTokens {
            return false
        }
        if lhs.temperature != rhs.temperature {
            return false
        }
        if lhs.topP != rhs.topP {
            return false
        }
        if lhs.topK != rhs.topK {
            return false
        }
        if lhs.repetitionPenalty != rhs.repetitionPenalty {
            return false
        }
        if lhs.systemPrompt != rhs.systemPrompt {
            return false
        }
        if lhs.backend != rhs.backend {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(maxTokens)
        hasher.combine(temperature)
        hasher.combine(topP)
        hasher.combine(topK)
        hasher.combine(repetitionPenalty)
        hasher.combine(systemPrompt)
        hasher.combine(backend)
    }
}



