/**
 * Errors crossing the FFI boundary. The `reason` strings carry the
 * underlying `anyhow` chain so host apps can log something actionable.
 *
 * The field is deliberately NOT named `message`: UniFFI maps error enums to
 * Kotlin exception classes, and a `message` field collides with
 * `Throwable.message` ("hides member of supertype" — the generated Kotlin
 * doesn't compile; found by the Android sample app).
 */
public enum SapientError: Swift.Error {

    
    
    case Load(reason: String
    )
    case Generation(reason: String
    )
    case InvalidArgument(reason: String
    )
    case Internal(reason: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeSapientError: FfiConverterRustBuffer {
    typealias SwiftType = SapientError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SapientError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Load(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 2: return .Generation(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 3: return .InvalidArgument(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 4: return .Internal(
            reason: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: SapientError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .Load(reason):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .Generation(reason):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .InvalidArgument(reason):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .Internal(reason):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(reason, into: &buf)
            
        }
    }
}


