    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ThermalLevel {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .nominal
        
        case 2: return .fair
        
        case 3: return .serious
        
        case 4: return .critical
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ThermalLevel, into buf: inout [UInt8]) {
        switch value {
        
        
        case .nominal:
            writeInt(&buf, Int32(1))
        
        
        case .fair:
            writeInt(&buf, Int32(2))
        
        
        case .serious:
            writeInt(&buf, Int32(3))
        
        
        case .critical:
            writeInt(&buf, Int32(4))
        
        }
    }
}


